from flask import Flask, request, jsonify
import face_recognition
import numpy as np
import os

app = Flask(__name__)

# Load and encode employee photos
def load_and_encode_images(image_folder):
    known_face_encodings = []
    known_face_names = []
    for filename in os.listdir(image_folder):
        if filename.endswith('.jpg') or filename.endswith('.png'):
            image_path = os.path.join(image_folder, filename)
            image = face_recognition.load_image_file(image_path)
            encoding = face_recognition.face_encodings(image)[0]
            known_face_encodings.append(encoding)
            known_face_names.append(os.path.splitext(filename)[0])
    return known_face_encodings, known_face_names

known_face_encodings, known_face_names = load_and_encode_images('employee_photos')

# API endpoint for facial recognition
@app.route('/recognize', methods=['POST'])
def recognize():
    file = request.files['image']
    unknown_image = face_recognition.load_image_file(file)
    unknown_encodings = face_recognition.face_encodings(unknown_image)

    if len(unknown_encodings) == 0:
        return jsonify({"error": "No face found in the image"}), 400

    unknown_encoding = unknown_encodings[0]
    face_distances = face_recognition.face_distance(known_face_encodings, unknown_encoding)
    face_probabilities = 1 - face_distances

    results = {}
    for name, probability in zip(known_face_names, face_probabilities):
        results[name] = probability

    return jsonify(results)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)